  title: 'MessageStrategy — context window management',
  group: 'providers',
  description: 'slidingWindow and charBudget — trim history to fit the context window.',
  defaultInput: '',
  providerSlots: [],
  tags: ['MessageStrategy', 'providers', 'context-window'],
